    # Pattern 1: Project name followed by (FEMA Project) or similar
    disaster_patterns = [
        r'([A-Za-z\s\-&/,]+?)\s*\(FEMA Project\)',
        r'([A-Za-z\s\-&/,]+?)\s*\(CalJPIA Project\)',
